```class Solution {
public:
    int maxLengthBetweenEqualCharacters(string s) {
        unordered_map<char, int> first, last;
        for (int i = 0; i < s.size(); ++i) {
            if (!first.count(s[i])) first[s[i]] = i;
            last[s[i]] = i;
        }
        int res = -1;
        for (auto& p : last) {
            if (p.second != first[p.first]) res = max(res, p.second - first[p.first] - 1);
        }
        return res;
    }
};
